def _materialised_view_to_nested(
    materialised_view: MaterialisedView,
) -> MaterialisedViewNested:
    """Convert flat MaterialisedView to nested format."""
    attrs = MaterialisedViewAttributes()
    _populate_materialised_view_attrs(attrs, materialised_view)
    # Categorize relationships by save semantic (REPLACE, APPEND, REMOVE)
    replace_rels, append_rels, remove_rels = categorize_relationships(
        materialised_view,
        _MATERIALISED_VIEW_REL_FIELDS,
        MaterialisedViewRelationshipAttributes,
    )
    return MaterialisedViewNested(
        guid=materialised_view.guid,
        type_name=materialised_view.type_name,
        status=materialised_view.status,
        version=materialised_view.version,
        create_time=materialised_view.create_time,
        update_time=materialised_view.update_time,
        created_by=materialised_view.created_by,
        updated_by=materialised_view.updated_by,
        classifications=materialised_view.classifications,
        classification_names=materialised_view.classification_names,
        meanings=materialised_view.meanings,
        labels=materialised_view.labels,
        business_attributes=materialised_view.business_attributes,
        custom_attributes=materialised_view.custom_attributes,
        pending_tasks=materialised_view.pending_tasks,
        proxy=materialised_view.proxy,
        is_incomplete=materialised_view.is_incomplete,
        provenance_type=materialised_view.provenance_type,
        home_id=materialised_view.home_id,
        depth=materialised_view.depth,
        immediate_upstream=materialised_view.immediate_upstream,
        immediate_downstream=materialised_view.immediate_downstream,
        attributes=attrs,
        relationship_attributes=replace_rels,
        append_relationship_attributes=append_rels,
        remove_relationship_attributes=remove_rels,
    )


def _materialised_view_from_nested(nested: MaterialisedViewNested) -> MaterialisedView:
    """Convert nested format to flat MaterialisedView."""
    attrs = (
        nested.attributes
        if nested.attributes is not UNSET
        else MaterialisedViewAttributes()
    )
    # Merge relationships from all three buckets
    merged_rels = merge_relationships(
        nested.relationship_attributes,
        nested.append_relationship_attributes,
        nested.remove_relationship_attributes,
        _MATERIALISED_VIEW_REL_FIELDS,
        MaterialisedViewRelationshipAttributes,
    )
    return MaterialisedView(
        guid=nested.guid,
        type_name=nested.type_name,
        status=nested.status,
        version=nested.version,
        create_time=nested.create_time,
        update_time=nested.update_time,
        created_by=nested.created_by,
        updated_by=nested.updated_by,
        classifications=nested.classifications,
        classification_names=nested.classification_names,
        labels=nested.labels,
        business_attributes=nested.business_attributes,
        custom_attributes=nested.custom_attributes,
        pending_tasks=nested.pending_tasks,
        proxy=nested.proxy,
        is_incomplete=nested.is_incomplete,
        provenance_type=nested.provenance_type,
        home_id=nested.home_id,
        depth=nested.depth,
        immediate_upstream=nested.immediate_upstream,
        immediate_downstream=nested.immediate_downstream,
        **_extract_materialised_view_attrs(attrs),
        # Merged relationship attributes
        **merged_rels,
    )


def _materialised_view_to_nested_bytes(
    materialised_view: MaterialisedView, serde: Serde
) -> bytes:
    """Convert flat MaterialisedView to nested JSON bytes."""
    return serde.encode(_materialised_view_to_nested(materialised_view))


def _materialised_view_from_nested_bytes(data: bytes, serde: Serde) -> MaterialisedView:
    """Convert nested JSON bytes to flat MaterialisedView."""
    nested = serde.decode(data, MaterialisedViewNested)
    return _materialised_view_from_nested(nested)


